import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface ReviewStats {
  day: string;
  reviews: number;
}

interface WidgetData {
  pendingReviews: number;
  averageReviewTime: number;
  weeklyReviewStats: ReviewStats[];
}

export default function Widget() {
  const data = response.data as WidgetData;
  const { pendingReviews, averageReviewTime, weeklyReviewStats } = data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#1F2937', color: '#F8FAFC' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#F59E0B' }}>
              Code Review Tracker
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8', mb: 0.5 }}>
              Pending Reviews
            </Typography>
            <Typography variant="h4" fontWeight={700}>
              {pendingReviews}
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8', mt: 0.5 }}>
              Avg. Review Time: {averageReviewTime} hrs
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: weeklyReviewStats.map(stat => stat.reviews),
                  color: '#F59E0B',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: weeklyReviewStats.map(stat => stat.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'reviews' }]}
            >
              <ChartsClipPath id={clipPathId} />
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsYAxis
                axisId="reviews"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
